import{_ as t,o as a,c as o,a4 as r}from"./chunks/framework.Bap02D_2.js";const u=JSON.parse('{"title":"ADR-004: No node-pty; restore proven via the RuntimeAdapter","description":"","frontmatter":{},"headers":[],"relativePath":"reference/decisions/ADR-004-no-node-pty.md","filePath":"reference/decisions/ADR-004-no-node-pty.md"}'),i={name:"reference/decisions/ADR-004-no-node-pty.md"};function n(s,e,d,l,c,h){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="adr-004-no-node-pty-restore-proven-via-the-runtimeadapter" tabindex="-1">ADR-004: No node-pty; restore proven via the RuntimeAdapter <a class="header-anchor" href="#adr-004-no-node-pty-restore-proven-via-the-runtimeadapter" aria-label="Permalink to &quot;ADR-004: No node-pty; restore proven via the RuntimeAdapter&quot;">​</a></h1><blockquote><p><strong>Date</strong>: 2026-06-28 <strong>Status</strong>: Accepted <strong>Source</strong>: RD-07 (host &amp; lifecycle), RD-09 (testing &amp; acceptance)</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>The host&#39;s most important guarantee is that the terminal is <strong>restored on every exit path</strong> — normal return, thrown error, and <code>SIGINT</code>/<code>SIGTERM</code>/<code>SIGHUP</code>. The obvious way to test this is to drive the program under a real pseudo-terminal via <code>node-pty</code>. But <code>node-pty</code> is a <strong>native</strong> dependency requiring node-gyp builds, which conflicts with the zero-native-dependency stance (<a href="/jsvision/pr-preview/pr-139/reference/decisions/ADR-001-esm-zero-dependency.html">ADR-001</a>).</p><h2 id="options-considered" tabindex="-1">Options Considered <a class="header-anchor" href="#options-considered" aria-label="Permalink to &quot;Options Considered&quot;">​</a></h2><h3 id="option-a-test-restore-with-a-real-pty-via-node-pty" tabindex="-1">Option A: Test restore with a real PTY via <code>node-pty</code> <a class="header-anchor" href="#option-a-test-restore-with-a-real-pty-via-node-pty" aria-label="Permalink to &quot;Option A: Test restore with a real PTY via `node-pty`&quot;">​</a></h3><ul><li><strong>Pros</strong>: Exercises the genuine TTY path end-to-end.</li><li><strong>Cons</strong>: Native dependency (node-gyp), cross-platform install fragility; violates the zero-native-dep policy even as a dev dep on all CI cells.</li></ul><h3 id="option-b-inject-a-runtimeadapter-verify-restore-with-a-fake-real-signal-e2e" tabindex="-1">Option B: Inject a <code>RuntimeAdapter</code>; verify restore with a fake + real-signal e2e <a class="header-anchor" href="#option-b-inject-a-runtimeadapter-verify-restore-with-a-fake-real-signal-e2e" aria-label="Permalink to &quot;Option B: Inject a `RuntimeAdapter`; verify restore with a fake + real-signal e2e&quot;">​</a></h3><ul><li><strong>Pros</strong>: No native dep; the restore logic is unit-tested against a fake adapter; a Tier-3 e2e spawns real child processes (<code>node --import tsx</code>) and delivers real signals to confirm restore without a PTY.</li><li><strong>Cons</strong>: The fake adapter must faithfully model the real TTY contract.</li></ul><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p><strong>Chosen option</strong>: Option B — the host runs behind an injectable <code>RuntimeAdapter</code>, and restore-on-every-exit is proven by unit tests with a fake adapter plus the RD-09 Tier-3 e2e using real OS signals — no <code>node-pty</code>.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>The restore guarantee is logic (&quot;on any exit, run the teardown sequence exactly once&quot;), and logic is best tested deterministically against a fake. The remaining risk — that signals actually trigger teardown — is covered by spawning real children and sending real <code>SIGTERM</code>/<code>SIGHUP</code>. This keeps the dependency surface pure (ADR-001) while still proving the behaviour that matters.</p><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h3 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">​</a></h3><ul><li>No native dependency anywhere in the toolchain; clean installs.</li><li>Restore logic is deterministically unit-tested; signals are covered by e2e.</li></ul><h3 id="negative" tabindex="-1">Negative <a class="header-anchor" href="#negative" aria-label="Permalink to &quot;Negative&quot;">​</a></h3><ul><li>The fake <code>RuntimeAdapter</code> must be kept faithful to the real TTY semantics.</li></ul><h3 id="risks" tabindex="-1">Risks <a class="header-anchor" href="#risks" aria-label="Permalink to &quot;Risks&quot;">​</a></h3><ul><li>A real-PTY resize/<code>SIGWINCH</code> corner is deferred (RD-09 DEF-3) — manually confirmed, automated PTY coverage left for later.</li></ul>',20)])])}const g=t(i,[["render",n]]);export{u as __pageData,g as default};
